/**
 * Knowledge Graph Domain Model
 *
 * Stores custom domains generated by LLM for industries not covered by built-in domains.
 * Tenant-scoped for security and isolation.
 */

import mongoose, { Schema, model } from 'mongoose';
import { uuidv7 } from '../mongo/base-document.js';
import { tenantIsolationPlugin } from '../mongo/plugins/tenant-isolation.plugin.js';
import { ModelRegistry } from '../model-registry.js';
import type {
  IKGCategory,
  IKGProduct,
  IKGAttribute,
  IKGDepartmentBoundary,
} from './knowledge-graph-taxonomy.model.js';

// ─── Document Interface ──────────────────────────────────────────────────

export interface IKnowledgeGraphDomain {
  _id: string;
  tenantId: string;
  name: string;
  version: string;
  industry: string;
  categories: IKGCategory[];
  products: IKGProduct[];
  attributes: IKGAttribute[];
  departmentBoundaries: IKGDepartmentBoundary[];
  createdBy: string; // User ID who created the domain
  createdAt: Date;
  updatedAt: Date;
}

// ─── Schema ──────────────────────────────────────────────────────────────

const KnowledgeGraphDomainSchema = new Schema<IKnowledgeGraphDomain>(
  {
    _id: { type: String, default: uuidv7 },
    tenantId: { type: String, required: true, index: true },
    name: {
      type: String,
      required: true,
      maxlength: 100,
      validate: {
        validator: (v: string) => /^[a-z0-9-]+$/.test(v),
        message: 'Domain name must be kebab-case',
      },
    },
    version: {
      type: String,
      required: true,
      validate: {
        validator: (v: string) => /^\d+\.\d+\.\d+$/.test(v),
        message: 'Version must be semver format (e.g., 1.0.0)',
      },
    },
    industry: { type: String, required: true, maxlength: 100 },

    categories: [
      {
        id: { type: String, required: true },
        name: { type: String, required: true },
        department: { type: String, required: true },
      },
    ],

    products: [
      {
        id: { type: String, required: true },
        name: { type: String, required: true },
        categoryId: { type: String, required: true },
        department: { type: String, required: true },
        subDepartment: { type: String, required: true },
        disambiguationKeywords: [{ type: String }],
        organizationSpecificNames: [{ type: String }],
        subProducts: [
          {
            id: { type: String, required: true },
            name: { type: String, required: true },
            disambiguationKeywords: [{ type: String }],
          },
        ],
      },
    ],

    attributes: [
      {
        id: { type: String, required: true },
        name: { type: String, required: true },
        dataType: {
          type: String,
          enum: ['percentage', 'currency', 'date', 'duration', 'identifier', 'string', 'number'],
          required: true,
        },
        applicableTo: [{ type: String }],
        notApplicableTo: [{ type: String }],
        extraction: {
          method: {
            type: String,
            enum: ['regex', 'llm', 'hybrid'],
            required: true,
          },
          patterns: [{ type: String }],
          keywords: [{ type: String }],
        },
        organizationContext: {
          typicalRange: { type: String },
          aliases: [{ type: String }],
        },
      },
    ],

    departmentBoundaries: [
      {
        product1: { type: String, required: true },
        product2: { type: String, required: true },
        reasoning: { type: String, required: true },
      },
    ],

    createdBy: { type: String, required: true },
  },
  { timestamps: true, collection: 'knowledge_graph_domains' },
);

// ─── Plugins ─────────────────────────────────────────────────────────────

KnowledgeGraphDomainSchema.plugin(tenantIsolationPlugin);

// ─── Indexes ─────────────────────────────────────────────────────────────

// Unique domain name per tenant
KnowledgeGraphDomainSchema.index({ tenantId: 1, name: 1 }, { unique: true });

// Recent domains first (for UI listing)
KnowledgeGraphDomainSchema.index({ tenantId: 1, createdAt: -1 });

// ─── Model ───────────────────────────────────────────────────────────────

// Register with ModelRegistry for dual-database support
ModelRegistry.registerModelDefinition(
  'KnowledgeGraphDomain',
  KnowledgeGraphDomainSchema,
  'searchaicontent',
);

export const KnowledgeGraphDomain =
  (mongoose.models.KnowledgeGraphDomain as any) ||
  model<IKnowledgeGraphDomain>('KnowledgeGraphDomain', KnowledgeGraphDomainSchema);
